/* ══════════════════════════════════════
       BLOCK: sidebar-theme-details
       Scoped under .block-sidebar-theme-details
       ══════════════════════════════════════ */

    body {
      font-family: 'Manrope', system-ui, sans-serif;
      margin: 0;
    }

    /* ── Card container ── */
    .block-sidebar-theme-details {
      background-color: hsl(var(--bg-surface, 0 0% 100%));
      border: 1px solid hsl(var(--card-border, 30 19% 90%));
      border-radius: var(--rounded-2xl, 16px);
      padding: var(--spacing-2xl, 30px);
      display: flex;
      flex-direction: column;
      overflow: hidden;
      width: 360px;
    }

    /* ── Header ── */
    .block-sidebar-theme-details__title {
      font-size: var(--text-base-font-size, 18px);
      line-height: var(--text-base-line-height, 20px);
      letter-spacing: var(--text-base-letter-spacing, 0px);
      font-weight: var(--font-weight-semibold, 600);
      color: hsl(var(--text-primary, 0 0% 9%));
      border-bottom: 1px dashed hsl(var(--border-1, 30 20% 94%));
      padding-bottom: var(--spacing-lg, 20px);
      margin: 0;
    }

    /* ── Styles for {{theme_details}} hook output ── */
    .block-sidebar-theme-details .theme-details {
      display: flex;
      flex-direction: column;
      padding-top: var(--spacing-lg, 20px);
    }

    .block-sidebar-theme-details .theme-detail-item {
      display: flex;
      align-items: center;
      gap: var(--spacing-md, 16px);
      /* entrance animation */
      opacity: 0;
      transform: translateY(12px);
      transition: opacity 0.4s cubic-bezier(0.16, 1, 0.3, 1),
                  transform 0.4s cubic-bezier(0.16, 1, 0.3, 1);
    }

    .block-sidebar-theme-details .theme-detail-item.visible {
      opacity: 1;
      transform: translateY(0);
    }

    .block-sidebar-theme-details .theme-detail-item__icon {
      width: var(--spacing-xl, 24px);
      height: var(--spacing-xl, 24px);
      flex-shrink: 0;
      object-fit: contain;
      opacity: 0.85;
    }

    .block-sidebar-theme-details .theme-detail-item__label {
      font-size: var(--text-sm-font-size, 15px);
      line-height: var(--text-sm-line-height, 20px);
      letter-spacing: var(--text-sm-letter-spacing, 0px);
      font-weight: var(--font-weight-regular, 400);
      color: hsl(var(--text-secondary, 0 0% 33%));
      white-space: nowrap;
    }

    .block-sidebar-theme-details .theme-detail-item__value {
      font-size: var(--text-sm-font-size, 15px);
      line-height: var(--text-sm-line-height, 20px);
      letter-spacing: var(--text-sm-letter-spacing, 0px);
      font-weight: var(--font-weight-regular, 400);
      color: hsl(var(--text-link, 227 72% 51%));
      white-space: nowrap;
    }

js:
// Inject preview data if hook placeholder is still present (standalone preview)
    const block = document.querySelector('.block-sidebar-theme-details');
    if (block && block.textContent.includes('{{theme_details}}')) {
      const tpl = document.getElementById('preview-data');
      if (tpl) {
        block.innerHTML = block.innerHTML.replace('{{theme_details}}', tpl.innerHTML);
      }
    }

    // Stagger reveal for detail items
    if (block) {
      const io = new IntersectionObserver((entries) => {
        entries.forEach(e => {
          if (e.isIntersecting) {
            e.target.classList.add('visible');
            io.unobserve(e.target);
          }
        });
      }, { threshold: 0.15 });
      block.querySelectorAll('.theme-detail-item').forEach((el, i) => {
        el.style.transitionDelay = `${i * 0.08}s`;
        io.observe(el);
      });
    }
